from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about astronauts (or related entities) into a
    fluent English sentence.  The function groups triples by their subject and
    builds a clause for each predicate, then joins the clauses into a single
    (or a few) readable sentences.
    """
    if not triples:
        return ""

    # Helper to turn a predicate/object pair into a descriptor (without repeating the subject)
    def phrase(subj: str, pred: str, obj: str) -> str:
        """Return a natural‑language descriptor for a single predicate."""
        obj = obj.strip().strip('"')
        p = pred.lower().replace(" ", "")
        def fmt_date(d: str) -> str:
            try:
                from datetime import datetime
                dt = datetime.strptime(d, "%Y-%m-%d")
                return dt.strftime("%B %-d, %Y")
            except Exception:
                return d

        if p == "birthdate":
            return f"was born on {fmt_date(obj)}"
        if p == "birthplace":
            return f"was born in {obj}"
        if p == "deathdate":
            return f"died on {fmt_date(obj)}"
        if p == "deathplace":
            return f"died in {obj}"
        if p == "nationality":
            # Return a phrase that can be used after the subject, e.g., "is American"
            low_obj = obj.lower()
            if low_obj in ("united states", "usa", "united states of america"):
                adj = "American"
            elif low_obj.startswith("the "):
                adj = obj[4:].strip()
            else:
                adj = obj
            return f"is {adj}"
        if p == "occupation":
            return f"was a {obj.lower()}"
        if p == "status":
            low = obj.lower()
            if low == "retired":
                return "is retired"
            return f"is {low}"
        if p == "selectedbynasa":
            return f"was selected by NASA in {obj}"
        if p == "mission":
            # Assume subject is an astronaut; describe crew membership in the mission,
            # and enrich with operator and other crew members if available.
            mission = obj.strip().strip('"')
            info = mission_info.get(mission, {})
            parts = [f"was a crew member of {mission}"]
            if info.get("operator"):
                parts.append(f"operated by {info['operator']}")
            # List other crew members (exclude the astronaut themselves if present)
            other_crew = [c for c in info.get("crew", []) if c != subj]
            if other_crew:
                parts.append("alongside " + ", ".join(other_crew))
            return " ".join(parts)
        if p == "timeinspace":
            try:
                mins = float(obj)
                hrs = int(mins // 60)
                rem = int(mins % 60)
                if hrs:
                    return f"spent {hrs} hour{'s' if hrs>1 else ''}" + (f" and {rem} minute{'s' if rem!=1 else ''}" if rem else "") + " in space"
                else:
                    return f"spent {rem} minute{'s' if rem!=1 else ''} in space"
            except Exception:
                return f"spent {obj} minutes in space"
        if p == "title":
            return f"held the title of {obj}"
        if p == "award":
            return f"received the {obj}"
        if p == "awards":
            return f"received {obj} awards"
        if p == "ribbonaward":
            return f"was awarded the {obj}"
        if p == "operator":
            return f"operated by {obj}"
        if p == "commander":
            # For mission subjects, express role succinctly
            return f"commander {obj}"
        if p == "backuppilot":
            return f"backup pilot {obj}"
        if p == "crewmembers":
            return f"crew member {obj}"
        if p == "leader":
            # Subject is an entity, object is a person
            return f"{obj} is the leader of {subj}"
        if p == "representative":
            return f"{obj} was the representative of {subj}"
        if p == "alternativename":
            return f"is also known as {obj}"
        if p == "servedaschiefoftheastronautofficein":
            return f"served as Chief of the Astronaut Office in {obj}"
        if p == "bird":
            return f"The {obj.lower()} is a bird found in {subj}"
        # Generic fallback
        return f"is {obj}"

    # Index triples by subject for cross‑reference (e.g., mission details)
    from collections import defaultdict
    triple_by_subject = defaultdict(list)
    for t in triples:
        triple_by_subject[t.subject].append(t)

    # Build auxiliary information for missions (operator, crew members, etc.)
    mission_info = defaultdict(lambda: {"operator": None, "crew": [], "commander": None, "backupPilot": None})
    for t in triples:
        p = t.predicate.lower().replace(" ", "")
        if p == "operator":
            mission_info[t.subject]["operator"] = t.object.strip().strip('"')
        elif p == "crewmembers":
            mission_info[t.subject]["crew"].append(t.object.strip().strip('"'))
        elif p == "commander":
            mission_info[t.subject]["commander"] = t.object.strip().strip('"')
        elif p == "backuppilot":
            mission_info[t.subject]["backupPilot"] = t.object.strip().strip('"')

    # Group triples by subject for sentence construction
    groups = defaultdict(list)
    for t in triples:
        groups[t.subject].append(t)

    sentences = []
    for subj, items in groups.items():
        # No special handling; treat all predicates uniformly
        subject_phrase = subj
        remaining_items = items

        descriptors = [phrase(subj, t.predicate, t.object) for t in remaining_items]
        if not descriptors:
            # Only nationality present
            sentences.append(f"{subject_phrase}.")
            continue
        if len(descriptors) == 1:
            sent = f"{subject_phrase} {descriptors[0]}."
        elif len(descriptors) == 2:
            # Two descriptors: join with 'and' without a preceding comma
            sent = f"{subject_phrase} {descriptors[0]} and {descriptors[1]}."
        else:
            # More than two descriptors: commas and final ', and'
            body = ", ".join(descriptors[:-1])
            sent = f"{subject_phrase} {body}, and {descriptors[-1]}."
        sentences.append(sent)

    # Combine sentences for different subjects
    return " ".join(sentences)

